library(shiny)

ui <- fluidPage(
  
  titlePanel("Random Normal Histogram"),
  
  sidebarLayout(
    sidebarPanel(
      sliderInput(
        "n",
        "Number of random values:",
        min = 10,
        max = 5000,
        value = 500,
        step = 10
      ),
      
      actionButton(
        "simulate",
        "Generate sample"
      )
    ),
    
    mainPanel(
      plotOutput("hist")
    )
  )
)

server <- function(input, output, session) {
  
  x <- eventReactive(input$simulate, {
    rnorm(input$n)
  }, ignoreInit = FALSE)
  
  output$hist <- renderPlot({
    hist(
      x(),
      breaks = 30,
      col = "lightblue",
      border = "white",
      main = paste("Histogram of", input$n, "N(0,1) draws"),
      xlab = ""
    )
  })
}

shinyApp(ui, server)
